const body = $input.first().json.body || $input.first().json;
const url = body.url || body.strona || '';
const email = body.email || '';
const firma = body.firma || 'Firma';
if (!url) throw new Error('Brak URL strony!');
return [{ json: { url, email, firma } }];

const html = $input.first().json.data || $input.first().json || '';
const url = $('Waliduj dane wejściowe').first().json.url;

// Podstawowe metryki z HTML
const hasTitle = /<title[^>]*>([^<]+)<\/title>/i.test(html);
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : 'Brak';

const metaDesc = /<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i.test(html);
const hasH1 = /<h1[^>]*>/i.test(html);
const h1Count = (html.match(/<h1[^>]*>/gi) || []).length;
const imgWithoutAlt = (html.match(/<img(?![^>]*alt=["'][^"']+["'])[^>]*>/gi) || []).length;
const hasSSL = url.startsWith('https://');
const hasViewport = /name=["']viewport["']/i.test(html);
const hasGTM = /googletagmanager|GTM-/i.test(html);
const hasGA = /google-analytics|gtag\(/i.test(html);
const hasFacebook = /facebook|fb\.com/i.test(html);
const hasStructuredData = /application\/ld\+json/i.test(html);
const hasCanonical = /<link[^>]+rel=["']canonical["']/i.test(html);
const pageSize = html.length;
const hasContactForm = /contact|kontakt|formularz|form/i.test(html);
const hasCTA = /zadzwo[nń]|kup teraz|zam[oó]w|bezp[łl]atna|kup|sprawdź|dowiedz/i.test(html);

return [{ json: {
  url, title, hasTitle, metaDesc, hasH1, h1Count,
  imgWithoutAlt, hasSSL, hasViewport, hasGTM, hasGA,
  hasFacebook, hasStructuredData, hasCanonical,
  pageSize, hasContactForm, hasCTA,
  htmlSnippet: html.substring(0, 3000)
}}];

